 1	import type { FC } from 'react';
 2	import { NetworkMapActionsDropdown } from 'src/modules/NetworkMaps/actions/NetworkMapActionsDropdown';
 3	import NetworkMapCriticalConditions from 'src/modules/NetworkMaps/components/NetworkMapCriticalConditions';
 4	import useGetDeleteAndEditAccessReview from 'src/modules/Providers/hooks/useGetDeleteAndEditAccessReview';
 5	import { PageHeadings } from 'src/modules/Providers/utils/components/DetailsPage/PageHeadings';
 6	
 7	import {
 8	  NetworkMapModel,
 9	  NetworkMapModelGroupVersionKind,
10	  type V1beta1NetworkMap,
11	} from '@kubev2v/types';
12	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
13	import { PageSection } from '@patternfly/react-core';
14	import { isEmpty } from '@utils/helpers';
15	
16	export const NetworkMapPageHeadings: FC<{ name: string; namespace: string }> = ({
17	  name,
18	  namespace,
19	}) => {
20	  const [obj, loaded, loadError] = useK8sWatchResource<V1beta1NetworkMap>({
21	    groupVersionKind: NetworkMapModelGroupVersionKind,
22	    name,
23	    namespace,
24	    namespaced: true,
25	  });
26	
27	  const permissions = useGetDeleteAndEditAccessReview({
28	    model: NetworkMapModel,
29	    namespace,
30	  });
31	
32	  const alerts = [];
33	
34	  const criticalCondition =
35	    loaded &&
36	    !loadError &&
37	    obj?.status?.conditions?.find((condition) => condition?.category === 'Critical');
38	
39	  if (criticalCondition) {
40	    alerts.push(
41	      <NetworkMapCriticalConditions
42	        type={criticalCondition?.type}
43	        message={criticalCondition?.message ?? ''}
44	        key={'mapCriticalCondition'}
45	      />,
46	    );
47	  }
48	
49	  return (
50	    <PageHeadings
51	      model={{ ...NetworkMapModel, label: 'Network map' }}
52	      obj={obj}
53	      namespace={namespace}
54	      actions={<NetworkMapActionsDropdown data={{ obj, permissions }} fieldId={''} fields={[]} />}
55	    >
56	      {!isEmpty(alerts) && (
57	        <PageSection variant="light" className="forklift-page-headings-alerts">
58	          {alerts}
59	        </PageSection>
60	      )}
61	    </PageHeadings>
62	  );
63	};

